
























































import { Vue, Component, Inject, Watch } from "vue-property-decorator";
import { SkillList, SkillCategory, BadgeLevel } from "@/models/skillList";
import { Mutation, State } from 'vuex-class';

@Component
export default class Skill extends Vue {
    @Inject("scroll") scrollOffset: any;
    @Mutation("menu") setMenu: any;
    @State("menu") menu: any;
  panel: number = 0;
  list: SkillCategory[] = SkillList;
  badgesColor = BadgeLevel;
  el: any = null;
  paperList: any=[];
  mounted() {
    this.el = this.$refs.el;
    
    this.randomPaper();
  }

  randomPaper(){
    let rnd=this.rand(24,32);
    for (var i=0; i< rnd; i++)
        this.paperList.push({
            top: this.rand()+'vh',
            left: this.rand()+'vw',
            width: this.rand(80,165)+"px",
            height: this.rand(80,140)+"px",
            rotate: 'rotate('+this.rand(-32,32)+'deg)',
            delay: (this.rand(0,4)*2+2)*100+"ms"
        });
  }

  scrollTo() {
    window.scrollTo({
      top: this.el.offsetTop+5,
      behavior: "smooth"
    });
  }
  
    rand(min: number=0, max: number=100): number{
        return Math.round(Math.random()*(max-min)+min);
    }
    get isInViewPort(){
        let offsetTop=0;
        let clientHeight=600;
        if (this.el) offsetTop=this.el.offsetTop;
        if (this.$el) clientHeight=this.$el.clientHeight;
        let result= this.offsetY>=offsetTop-clientHeight*0.4 && this.offsetY<=offsetTop+clientHeight-clientHeight*0.5;
        if (result && this.el){
            this.setMenu("skill");
            this.el.style.minHeight=this.el.clientHeight+"px";
        }
        return result;
    }

    // timer: number=0;
    // @Watch("isInViewPort")
    // viewPortChanged(){
    //     if (this.timer)
    //         clearTimeout(this.timer)
    //     if (this.isInViewPort){
    //     this.timer=setTimeout(()=>{
    //         if (this.isInViewPort && this.el){
    //             this.setMenu("intro");
    //             this.scrollTo();
    //         }
    //         this.timer=0;
    //     },100);
    //     }
    // }

    get offsetY(){
        return this.scrollOffset.offsetY;
    }
    get size(){
        return this.scrollOffset.size;
    }
}
